import{_ as a,o as t,c as r,ai as o}from"./chunks/framework.Dazo0ijd.js";const l=JSON.parse('{"title":"架构演进","description":"","frontmatter":{"title":"架构演进","order":30},"headers":[],"relativePath":"design/spacetime/general/architecture.md","filePath":"design/spacetime/general/architecture.md"}'),i={name:"design/spacetime/general/architecture.md"};function n(s,e,d,c,p,u){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="架构演进" tabindex="-1">架构演进 <a class="header-anchor" href="#架构演进" aria-label="Permalink to “架构演进”">​</a></h1><p>现代架构模式的演进有一条清晰的主线：把业务逻辑放在中心，把技术细节推到外围。围绕这条主线，架构流派从&quot;分层&quot;逐步走向&quot;内外&quot;，核心问题始终是同一个——如何让业务核心不被技术实现污染。</p><h2 id="六边形架构" tabindex="-1">六边形架构 <a class="header-anchor" href="#六边形架构" aria-label="Permalink to “六边形架构”">​</a></h2><p>传统的分层架构把系统分成上下层，但六边形架构认为系统不该分上下，而该分内外：业务逻辑（Domain）居于内部，通过&quot;端口&quot;（Ports）与外界通信，而数据库、HTTP 接口、消息队列都是外接的&quot;适配器&quot;（Adapters）。换一个数据库就像换一个插头，不影响核心逻辑。</p><p>这种&quot;内外&quot;切分的好处是业务逻辑完全不依赖技术实现，技术栈迁移或新增访问渠道时，核心代码无需改动。这与<a href="./container">容器</a>作为治理边界的思路是一致的：业务核心是边界内部被精心治理的资源，技术细节是边界外可替换的适配器。</p><h2 id="整洁架构" tabindex="-1">整洁架构 <a class="header-anchor" href="#整洁架构" aria-label="Permalink to “整洁架构”">​</a></h2><p>整洁架构是六边形思想的进一步系统化，核心是一条依赖规则：依赖只能从外向内指向。最内层的实体（Entities）最稳定、最抽象，最外层的框架（Frameworks）最易变；每一层都只能依赖比自己更内、更稳定的层。</p><p>这条规则把&quot;稳定性&quot;和&quot;位置&quot;绑死：越往内越稳定越抽象，越往外越易变越具体。于是<a href="./../process/coupling">组件耦合</a>中的 SDP 和 SAP 在这里被具象成了一种空间布局——把稳定抽象的东西放进核心，把易变具体的东西留在边缘。</p><h2 id="ddd-领域驱动设计" tabindex="-1">DDD：领域驱动设计 <a class="header-anchor" href="#ddd-领域驱动设计" aria-label="Permalink to “DDD：领域驱动设计”">​</a></h2><p>如果说 SOLID 教我们写好一个类，DDD 教我们设计一个复杂的业务系统。它有两件法宝。</p><p>统一语言（Ubiquitous Language）要求程序员和业务方用同一套词汇交流，代码里的类名要和业务名词对齐。这种对齐不是简单的命名映射，而是对业务领域的深入建模——当业务方说&quot;退款&quot;而代码里只有 RefundOrder 时，模型和现实之间的缝隙就已经在制造 bug 了。</p><p>限界上下文（Bounded Context）是 DDD 的核心。它强调明确边界：同一个&quot;商品&quot;，在仓库系统里关注库存，在营销系统里关注价格。DDD 用边界来隔离同一个概念在不同上下文里的不同含义，这与<a href="./../process/scope">作用域</a>划分的思路高度契合。</p><h2 id="边界即最难" tabindex="-1">边界即最难 <a class="header-anchor" href="#边界即最难" aria-label="Permalink to “边界即最难”">​</a></h2><p>回看这些流派，技术细节千差万别，但内核都是同一件事：划定边界。架构设计最难的部分从来不是写代码，而是判断这条边界该划在哪里——划得太大，系统臃肿难改；划得太碎，协作成本爆炸。所有的架构原则，本质上都是在回答&quot;什么该被关进同一条边界里&quot;。</p>',14)])])}const q=a(i,[["render",n]]);export{l as __pageData,q as default};
